from functools import wraps
import time
import logging
import sys

# Set up logging
logging.basicConfig(level=logging.DEBUG)

def retry(tries=10, delay=1, backoff=2, retry_exception=None):
    """
    Retry "tries" times, with initial "delay", increasing delay "delay*backoff" each time.
    Without exception success means when function returns valid object.
    With exception success when no exceptions
    """
    assert tries > 0, "tries must be 1 or greater"
    catching_mode = bool(retry_exception)

    def deco_retry(f):
        @wraps(f)
        def f_retry(*args, **kwargs):
            mtries, mdelay = tries, delay

            while mtries > 0:
                time.sleep(mdelay)
                mdelay *= backoff
                try:
                    rv = f(*args, **kwargs)
                    if not catching_mode and rv:
                        return rv
                except retry_exception:
                    pass
                else:
                    if catching_mode:
                        return rv
                mtries -= 1
                if mtries is 0 and not catching_mode:
                    return False
                if mtries is 0 and catching_mode:
                    return f(*args, **kwargs)  # extra try, to avoid except-raise syntax
                logging.debug("{0} try, sleeping for {1} sec".format(tries-mtries, mdelay))
            raise Exception("unreachable code")
        return f_retry
    return deco_retry

# Example usage:
@retry(tries=3, delay=1, backoff=2)
def add_user(dn: str, mod_list: dict) -> None:
    # Simulate a failed operation
    if dn == "failed_user":
        raise Exception("Failed to add user")
    # Simulate a successful operation
    return None

try:
    add_user("successful_user", {"cn": "John Doe"})
except Exception as e:
    print(f"Failed to add user: {e}")

try:
    add_user("failed_user", {"cn": "Jane Doe"})
except Exception as e:
    print(f"Failed to add user: {e}")
```

In this example, the `retry` function is used to retry the `add_user` function 3 times with a delay of 1 second and a backoff of 2. If the operation fails, it will be retried until it succeeds or the maximum number of tries
